// Extract workflow metadata
const workflow = $json;

return {
  json: {
    original_workflow: JSON.stringify(workflow),
    workflow_name: workflow.name,
    workflow_id: workflow.id,
    nodes_json: JSON.stringify(workflow.nodes),
    node_count: workflow.nodes ? workflow.nodes.length : 0,
    is_active: workflow.active || false
  }
};

// Apply sanitization
let findings = [];
try {
  const output = $json.output || '{}';
  findings = JSON.parse(output);
  if (!Array.isArray(findings)) {
    findings = [];
  }
} catch (e) {
  console.log('Parse error:', e.message);
  findings = [];
}

const workflowStr = $node["Extract Metadata"].json.original_workflow;
let sanitized = workflowStr;
const replacements = [];

for (const finding of findings) {
  if (!finding.original_value) continue;
  const regex = new RegExp(finding.original_value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g');
  const before = sanitized;
  sanitized = sanitized.replace(regex, finding.template_variable);

  if (before !== sanitized) {
    replacements.push(finding);
  }
}

return {
  json: {
    sanitized_workflow: sanitized,
    replacements: replacements,
    replacement_count: replacements.length
  }
};

// Analyze workflow complexity
const nodeCount = $node["Extract Metadata"].json.node_count;
const nodesStr = $node["Extract Metadata"].json.nodes_json || '[]';
let nodes = [];
try {
  nodes = JSON.parse(nodesStr);
} catch (e) {
  nodes = [];
}

const httpNodes = nodes.filter(n => n.type === 'n8n-nodes-base.httpRequest').length;
const aiNodes = nodes.filter(n => (n.type || '').includes('langchain') || (n.type || '').includes('anthropic') || (n.type || '').includes('openAi')).length;
const conditionalNodes = nodes.filter(n => n.type === 'n8n-nodes-base.if' || n.type === 'n8n-nodes-base.switch').length;

let score = 1;
if (nodeCount > 50) score += 4;
else if (nodeCount > 30) score += 3;
else if (nodeCount > 15) score += 2;
else if (nodeCount > 5) score += 1;

score += Math.min(httpNodes * 0.5, 3);
score += Math.min(aiNodes * 0.3, 2);
score += Math.min(conditionalNodes * 0.2, 1);
score = Math.min(Math.round(score * 10) / 10, 10);

const buildTime = Math.max(2, Math.round(nodeCount * 0.3 + httpNodes * 0.5 + aiNodes * 1.5));
const setupTime = Math.max(15, $node["Apply Sanitization"].json.replacement_count * 3 + 10);

return {
  json: {
    complexity_score: score,
    node_count: nodeCount,
    integration_count: httpNodes,
    ai_node_count: aiNodes,
    build_time_hours: buildTime,
    setup_time_minutes: setupTime,
    complexity_level: score < 4 ? 'Simple' : score < 7 ? 'Moderate' : 'Complex'
  }
};

